    {"path": "aragami-2-trainer/trainer/memory_utils.py", "content": "\"\"\"\nMemory utility module for Aragami 2 Trainer.\nProvides low-level memory operations using pymem for the Aragami 2 process.\n\"\"\"\nimport pymem\nimport pymem.process\nimport struct\nfrom typing import Optional, Tuple\n\nclass MemoryUtils:\n    \"\"\"Handles memory reading/writing for Aragami 2 game process.\"\"\"\n    \n    # Known offsets for Aragami 2 (version 1.0.5.0)\n    # These are example offsets and would need to be updated per game version\n    OFFSETS = {\n        \"health\": 0x00A1B2C0,\n        \"shadow_energy\": 0x00A1B2C4,\n        \"max_health\": 0x00A1B2C8,\n        \"max_shadow_energy\": 0x00A1B2CC,\n        \"invisibility_timer\": 0x00A1B2D0,\n        \"score\": 0x00A1B2D4,\n        \"stealth_mode\": 0x00A1B2D8,\n    }\n    \n    def __init__(self):\n        self.pm: Optional[pymem.Pymem] = None\n        self.process_handle = None\n        self.base_address = None\n        self.initialized = False\n    \n    def attach_to_process(self) -> bool:\n        \"\"\"Attach to the Aragami 2 process.\"\"\"\n        try:\n            self.pm = pymem.Pymem(\"Aragami2-Win64-Shipping.exe\")\n            self.process_handle = self.pm.process_handle\n            self.base_address = pymem.process.module_from_name(\n                self.pm.process_handle, \n                \"Aragami2-Win64-Shipping.exe\"\n            ).lpBaseOfDll\n            self.initialized = True\n            return True\n        except pymem.exception.ProcessNotFound:\n            return False\n        except Exception as e:\n            print(f\"Error attaching to process: {e}\")\n            return False\n    \n    def read_float(self, address: int) -> Optional[float]:\n        \"\"\"Read a float value from a given memory address.\"\"\"\n        try:\n            raw_bytes = self.pm.read_bytes(address, 4)\n            return struct.unpack('f', raw_bytes)[0]\n        except Exception:\n            return None\n    \n    def write_float(self, address: int, value: float) -> bool:\n        \"\"\"Write a float value to a given memory address.\"\"\"\n        try:\n            raw_bytes = struct.pack('f', value)\n            self.pm.write_bytes(address, raw_bytes, 4)\n            return True\n        except Exception:\n            return False\n    \n    def read_int(self, address: int) -> Optional[int]:\n        \"\"\"Read an integer value from a given memory address.\"\"\"\n        try:\n            raw_bytes = self.pm.read_bytes(address, 4)\n            return struct.unpack('i', raw_bytes)[0]\n        except Exception:\n            return None\n    \n    def write_int(self, address: int, value: int) -> bool:\n        \"\"\"Write an integer value to a given memory address.\"\"\"\n        try:\n            raw_bytes = struct.pack('i', value)\n            self.pm.write_bytes(address, raw_bytes, 4)\n            return True\n        except Exception:\n            return False\n    \n    def get_absolute_address(self, offset: int) -> Optional[int]:\n        \"\"\"Calculate absolute address from base address and offset.\"\"\"\n        if self.base_address is None:\n            return None\n        return self.base_address + offset\n    \n    def read_health(self) -> Optional[float]:\n        \"\"\"Read current health value.\"\"\"\n        addr = self.get_absolute_address(self.OFFSETS[\"health\"])\n        if addr:\n            return self.read_float(addr)\n        return None\n    \n    def write_health(self, value: float) -> bool:\n        \"\"\"Write health value (for infinite health cheat).\"\"\"\n        addr = self.get_absolute_address(self.OFFSETS[\"health\"])\n        if addr:\n            return self.write_float(addr, value)\n        return False\n    \n    def read_shadow_energy(self) -> Optional[float]:\n        \"\"\"Read current shadow energy value.\"\"\"\n        addr = self.get_absolute_address(self.OFFSETS[\"shadow_energy\"])\n        if addr:\n            return self.read_float(addr)\n        return None\n    \n    def write_shadow_energy(self, value: float) -> bool:\n        \"\"\"Write shadow energy value (for infinite energy cheat).\"\"\"\n        addr = self.get_absolute_address(self.OFFSETS[\"shadow_energy\"])\n        if addr:\n            return self.write_float(addr, value)\n        return False\n    \n    def write_invisibility_timer(self, value: float) -> bool:\n        \"\"\"Set invisibility timer (for permanent invisibility).\"\"\"\n        addr = self.get_absolute_address(self.OFFSETS[\"invisibility_timer\"])\n        if addr:\n            return self.write_float(addr, value)\n        return False\n    \n    def write_stealth_mode(self, value: int) -> bool:\n        \"\"\"Toggle stealth mode (1 = always stealth, 0 = normal).\"\"\"\n        addr = self.get_absolute_address(self.OFFSETS[\"stealth_mode\"])\n        if addr:\n            return self.write_int(addr, value)\n        return False\n    \n    def detach(self):\n        \"\"\"Detach from the process.\"\"\"\n        if self.pm:\n            self.pm.close_process()\n        self.initialized = False\n        self.pm = None\n        self.base_address = None\n"},
    {"path": "aragami-2-trainer/trainer/trainer_core.py", "content": "\"\"\"\nCore trainer module for Aragami 2 Trainer.\nManages cheat features and hotkey bindings.\n\"\"\"\nimport threading\nimport time\nfrom typing import Dict, Callable, Optional\nfrom pynput import keyboard\nfrom colorama import Fore, Style, init as colorama_init\nfrom .memory_utils import MemoryUtils\n\n# Initialize colorama for colored console output\ncolorama_init(autoreset=True)\n\nclass TrainerCore:\n    \"\"\"Main trainer class that manages all cheat functionalities.\"\"\"\n    \n    def __init__(self):\n        self.mem = MemoryUtils()\n        self.active_cheats: Dict[str, bool] = {\n            \"infinite_health\": False,\n            \"infinite_shadow_energy\": False,\n            \"permanent_invisibility\": False,\n            \"always_stealth\": False,\n        }\n        self.listener: Optional[keyboard.Listener] = None\n        self.running = False\n        self.cheat_thread: Optional[threading.Thread] = None\n        \n        # Hotkey bindings\n        self.hotkeys = {\n            \"<ctrl>+h\": self.toggle_infinite_health,\n            \"<ctrl>+e\": self.toggle_infinite_energy,\n            \"<ctrl>+i\": self.toggle_invisibility,\n            \"<ctrl>+s\": self.toggle_stealth,\n            \"<ctrl>+q\": self.quit_trainer,\n        }\n    \n    def print_status(self, message: str, color: str = Fore.GREEN):\n        \"\"\"Print a colored status message to the console.\"\"\"\n        print(f\"{color}[Trainer] {message}{Style.RESET_ALL}\")\n    \n    def toggle_cheat(self, cheat_name: str) -> bool:\n        \"\"\"Toggle a cheat on/off.\"\"\"\n        if cheat_name not in self.active_cheats:\n            return False\n        self.active_cheats[cheat_name] = not self.active_cheats[cheat_name]\n        state = \"ON\" if self.active_cheats[cheat_name] else \"OFF\"\n        color = Fore.GREEN if self.active_cheats[cheat_name] else Fore.RED\n        self.print_status(f\"{cheat_name.replace('_', ' ').title()}: {state}\", color)\n        return True\n    \n    def toggle_infinite_health(self):\n        \"\"\"Toggle infinite health cheat.\"\"\"\n        self.toggle_cheat(\"infinite_health\")\n    \n    def toggle_infinite_energy(self):\n        \"\"\"Toggle infinite shadow energy cheat.\"\"\"\n        self.toggle_cheat(\"infinite_shadow_energy\")\n    \n    def toggle_invisibility(self):\n        \"\"\"Toggle permanent invisibility cheat.\"\"\"\n        self.toggle_cheat(\"permanent_invisibility\")\n    \n    def toggle_stealth(self):\n        \"\"\"Toggle always stealth mode cheat.\"\"\"\n        self.toggle_cheat(\"always_stealth\")\n    \n    def quit_trainer(self):\n        \"\"\"Quit the trainer gracefully.\"\"\"\n        self.print_status(\"Shutting down trainer...\", Fore.YELLOW)\n        self.running = False\n        return False  # Stop the listener\n    \n    def apply_cheats(self):\n        \"\"\"Apply active cheats in a loop.\"\"\"\n        while self.running:\n            try:\n                if self.active_cheats[\"infinite_health\"]:\n                    max_hp = self.mem.read_float(\n                        self.mem.get_absolute_address(self.mem.OFFSETS[\"max_health\"])\n                    )\n                    if max_hp is not None:\n                        self.mem.write_health(max_hp)\n                \n                if self.active_cheats[\"infinite_shadow_energy\"]:\n                    max_se = self.mem.read_float(\n                        self.mem.get_absolute_address(self.mem.OFFSETS[\"max_shadow_energy\"])\n                    )\n                    if max_se is not None:\n                        self.mem.write_shadow_energy(max_se)\n                \n                if self.active_cheats[\"permanent_invisibility\"]:\n                    self.mem.write_invisibility_timer(999.0)\n                \n                if self.active_cheats[\"always_stealth\"]:\n                    self.mem.write_stealth_mode(1)\n                \n                time.sleep(0.1)  # Prevent CPU overload\n            except Exception as e:\n                self.print_status(f\"Error applying cheats: {e}\", Fore.RED)\n                time.sleep(1)\n    \n    def on_press(self, key):\n        \"\"\"Handle key press events for hotkeys.\"\"\"\n        # This is a simplified handler; pynput's GlobalHotKeys is used instead\n        pass\n    \n    def start(self):\n        \"\"\"Start the trainer.\"\"\"\n        self.print_status(\"Attaching to Aragami 2 process...\", Fore.CYAN)\n        if not self.mem.attach_to_process():\n            self.print_status(\"Failed to attach to Aragami 2. Is the game running?\", Fore.RED)\n            return\n        \n        self.print_status(\"Trainer loaded successfully!\", Fore.GREEN)\n        self.print_status(\"Hotkeys:\", Fore.CYAN)\n        for hotkey, action in self.hotkeys.items():\n            desc = action.__name__.replace('_', ' ').title()\n            self.print_status(f\"  {hotkey}: {desc}\", Fore.YELLOW)\n        \n        self.running = True\n        \n        # Start cheat application thread\n        self.cheat_thread = threading.Thread(target=self.apply_cheats, daemon=True)\n        self.cheat_thread.start()\n        \n        # Start hotkey listener\n        with keyboard.GlobalHotKeys(self.hotkeys) as self.listener:\n            self.listener.join()\n        \n        self.mem.detach()\n        self.print_status(\"Trainer stopped.\", Fore.YELLOW)\n"},
    {"path": "aragami-2-trainer/main.py", "content": "#!/usr/bin/env python3\n\"\"\"\nAragami 2 Trainer - Main entry point.\nA memory-based trainer for the game Aragami 2.\n\"\"\"\nimport sys\nimport os\nfrom trainer import TrainerCore\n\ndef main():\n    \"\"\"Main function to run the Aragami 2 Trainer.\"\"\"\n    # Ensure we are running on Windows (required for pymem)\n    if sys.platform != \"win32\":\n        print(\"Error: Aragami 2 Trainer is only supported on Windows.\")\n        sys.exit(1)\n    \n    # Check if game process exists (optional, will be checked in TrainerCore)\n    print(\"=\" * 50)\n    print(\"   Aragami 2 Trainer v1.0.0\")\n    print(\"   Use at your own risk!\")\n    print(\"=\" * 50)\n    \n    trainer = TrainerCore()\n    try:\n        trainer.start()\n    except KeyboardInterrupt:\n        print(\"\\nTrainer interrupted by user.\")\n        trainer.running = False\n    except Exception as e:\n        print(f\"Fatal error: {e}\")\n        sys.exit(1)\n    finally:\n        if trainer.mem.initialized:\n            trainer.mem.detach()\n        print(\"Exiting trainer. Goodbye!\")\n\nif __name__ == \"__main__\":\n    main()\n"},
